import type Accessor from "@arcgis/core/core/Accessor.js";
import type Collection from "@arcgis/core/core/Collection.js";
import type SceneView from "@arcgis/core/views/SceneView.js";
import type Slide from "@arcgis/core/webscene/Slide.js";

/** @internal */
export interface PresentationViewModelProperties extends Partial<Pick<PresentationViewModel, "keyboardNavigationEnabled" | "slideId" | "view">> {}

/** @internal */
export default class PresentationViewModel extends Accessor {
  constructor(properties?: PresentationViewModelProperties);
  get firstSlideSelected(): boolean;
  get hasOnlyOneSlide(): boolean;
  /**
   * Enable navigation with the keyboard
   * by using the arrow keys or page up/page down keys
   *
   * @default false
   */
  accessor keyboardNavigationEnabled: boolean;
  get lastSlideSelected(): boolean;
  accessor slideId: string | undefined;
  get slideIndex(): number;
  get slideSelected(): boolean;
  accessor view: SceneView | undefined;
  get visibleSlides(): Collection<Slide>;
  /**
   * @param event
   * @param direction
   */
  captureArrowKeysForNavigation(event: KeyboardEvent, direction: "ltr" | "rtl"): void;
  destroy(): void;
  /** @param slideId */
  getSlideIndexBySlideId(slideId: string | undefined): number;
  initialize(): void;
  /** @param stepSize */
  navigateInPresentation(stepSize: number): void;
}